import pandas as pd
import json
import os
from datetime import datetime


def generate_html_dashboard(csv_file: str = "results.csv", output: str = "dashboard.html") -> None:
    try:
        df = pd.read_csv(csv_file)
    except FileNotFoundError:
        print(f"[Dashboard] No se encontro '{csv_file}'"); return
    except Exception as e:
        print(f"[Dashboard] Error: {e}"); return

    if df.empty:
        print("[Dashboard] Sin datos."); return

    names      = df["name"].tolist()
    prices_raw = df["price_raw"].tolist()

    def clean_price(p):
        try: return float(str(p).replace("$","").replace(",","").strip())
        except: return 0.0

    prices      = [clean_price(p) for p in prices_raw]
    ratings_raw = df["rating"].tolist()
    ratings     = [int(r) if str(r).isdigit() else 0 for r in ratings_raw]

    valid_prices  = [p for p in prices if p > 0]
    avg_price     = round(sum(valid_prices)/len(valid_prices), 2) if valid_prices else 0
    max_price     = max(valid_prices) if valid_prices else 0
    min_price     = min(valid_prices) if valid_prices else 0
    valid_ratings = [r for r in ratings if r > 0]
    avg_rating    = round(sum(valid_ratings)/len(valid_ratings), 2) if valid_ratings else 0
    rating_dist   = {str(i): ratings.count(i) for i in range(1, 6)}
    timestamp     = datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    rows_html = ""
    for _, row in df.iterrows():
        rval = row.get("rating", "N/A")
        rnum = 0
        try: rnum = int(rval); stars = "★"*rnum + "☆"*(5-rnum)
        except: stars = "N/A"
        pnum      = clean_price(row.get("price_raw", 0))
        cat       = str(row.get("category", "N/A"))
        cat_label = cat.split("/")[-1].capitalize()
        name      = str(row.get("name", ""))
        desc      = str(row.get("description", ""))[:60]
        rows_html += (
            '<tr data-category="' + cat + '" data-price="' + str(pnum) + '"'
            ' data-rating="' + str(rnum) + '" data-name="' + name.replace('"','').replace("'",'') + '">'
            '<td>' + name + '</td>'
            '<td class="price">' + str(row.get("price_raw","")) + '</td>'
            '<td class="rating-stars">' + stars + '</td>'
            '<td>' + desc + '...</td>'
            '<td><span class="cat-badge">' + cat_label + '</span></td>'
            '</tr>'
        )

    LOGO = "data:image/jpeg;base64,"

    chart_data = (
        "<script>\n"
        "  window.CHART_DATA = {\n"
        "    names: "     + json.dumps(names)       + ",\n"
        "    prices: "    + json.dumps(prices)      + ",\n"
        "    ratingDist: "+ json.dumps(rating_dist) + "\n"
        "  };\n"
        "</script>\n"
    )

    html = (
        "<!DOCTYPE html>\n"
        '<html lang="es">\n'
        "<head>\n"
        '<meta charset="UTF-8">\n'
        '<meta name="viewport" content="width=device-width, initial-scale=1.0">\n'
        "<title> Dashboard - Banco de Bogota</title>\n"
        '<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.min.js"></script>\n'
        '<link rel="stylesheet" href="static/estilos/dashboard.css">\n'
        "</head>\n<body>\n"
        "<header>\n"
        "  <div class=\"header-left\">\n"
        '    <img src="' + LOGO + '" width="52" height="52"'
        ' style="border-radius:8px;display:block;box-shadow:0 2px 8px rgba(0,48,135,0.18);"'
        ' alt="Banco de Bogota">\n'
        "    <div>\n"
        '      <div class="header-brand">Banco de Bogota</div>\n'
        "      <h1><span>Dashboard</span></h1>\n"
        "    </div>\n"
        "  </div>\n"
        '  <div class="timestamp">Jhon Esteban Tellez Gracia - Prueba Tecnica - Generado: ' + timestamp + "</div>\n"
        "</header>\n"
        '<div class="stats-grid">\n'
        '  <div class="stat-card"><div class="stat-label">Total Productos</div>'
        '<div class="stat-value">' + str(len(df)) + "</div></div>\n"
        '  <div class="stat-card"><div class="stat-label">Precio Promedio</div>'
        '<div class="stat-value">$' + str(avg_price) + "</div></div>\n"
        '  <div class="stat-card"><div class="stat-label">Rating Promedio</div>'
        '<div class="stat-value">' + str(avg_rating) + "&#9733;</div></div>\n"
        '  <div class="stat-card"><div class="stat-label">Rango de Precio</div>'
        '<div class="stat-value">$' + str(min_price) + "&ndash;$" + str(max_price) + "</div></div>\n"
        "</div>\n"
        '<div class="charts-grid">\n'
        '  <div class="chart-card"><h3>Precio por Producto</h3>'
        '<div class="chart-container"><canvas id="priceChart"></canvas></div></div>\n'
        '  <div class="chart-card"><h3>Distribucion de Ratings</h3>'
        '<div class="chart-container"><canvas id="ratingChart"></canvas></div></div>\n'
        "</div>\n"
        '<div class="table-card">\n'
        "  <h3>Todos los Productos</h3>\n"
        '  <div class="controls">\n'
        '    <input type="text" id="searchInput" placeholder="Buscar producto...">\n'
        '    <select id="categoryFilter"><option value="">Todas las categorias</option></select>\n'
        '    <select id="ratingFilter">\n'
        '      <option value="">Todos los ratings</option>\n'
        '      <option value="5">5 estrellas</option>\n'
        '      <option value="4">4+ estrellas</option>\n'
        '      <option value="3">3+ estrellas</option>\n'
        '      <option value="2">2+ estrellas</option>\n'
        '      <option value="1">1+ estrella</option>\n'
        "    </select>\n"
        '    <span id="countLabel"></span>\n'
        "  </div>\n"
        '<table id="productsTable">\n'
        "  <thead><tr>\n"
        '    <th class="sortable" data-col="name">Nombre</th>\n'
        '    <th class="sortable" data-col="price">Precio</th>\n'
        '    <th class="sortable" data-col="rating">Rating</th>\n'
        "    <th>Descripcion</th>\n"
        '    <th class="sortable" data-col="category">Categoria</th>\n'
        "  </tr></thead>\n"
        '  <tbody id="tableBody">' + rows_html + "</tbody>\n"
        "</table>\n"
        "</div>\n"
        '<footer>Kata Middle — Jhon Esteban Tellez Gracia - Prueba Tecnica | ' + timestamp + "</footer>\n"
        + chart_data +
        '<script src="static/js/charts.js"></script>\n'
        '<script src="static/js/table.js"></script>\n'
        "</body>\n</html>\n"
    )

    with open(output, "w", encoding="utf-8") as f:
        f.write(html)

    print(f"  Dashboard generado: '{output}'")
